components.OutflowTimeline:
export default function OutflowTimeline() {
  const [scheduled, setScheduled] = useState([]);
  const [recurring, setRecurring] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      tools.host_listScheduledPayments({}),
      tools.host_getRecurringInsights({})
    ]).then(([sched, rec]) => {
      setScheduled(sched.data || sched.payments || sched || []);
      setRecurring(rec.subscriptions || rec.recurring || rec.data || []);
      setLoading(false);
    });
  }, []);

  if (loading) {
    return (
      <div style={{ padding: 24, color: "var(--vendo-color-muted)", fontFamily: "var(--vendo-font-family)" }}>
        Loading upcoming payments…
      </div>
    );
  }

  const today = new Date("2026-07-21");

  const schedItems = (Array.isArray(scheduled) ? scheduled : []).map((p) => ({
    id: "sched-" + (p.id || p.payeeId || Math.random()),
    label: p.payeeName || p.name || p.descriptor || "Scheduled payment",
    amountCents: p.amountCents || p.amount || 0,
    date: p.scheduledDate || p.date || p.nextDate || null,
    type: "scheduled",
  }));

  const recItems = (Array.isArray(recurring) ? recurring : []).map((r) => ({
    id: "rec-" + (r.id || r.merchant || Math.random()),
    label: r.merchant || r.name || r.descriptor || "Subscription",
    amountCents: r.amountCents || r.amount || 0,
    date: r.nextDate || r.nextBillingDate || r.date || null,
    type: "subscription",
  }));

  const allItems = [...schedItems, ...recItems]
    .filter((item) => item.date)
    .sort((a, b) => new Date(a.date) - new Date(b.date));

  const totalCents = allItems.reduce((sum, item) => sum + (item.amountCents || 0), 0);

  const formatMoney = (cents) => {
    if (!cents && cents !== 0) return "—";
    return fmt.money(cents);
  };

  const formatDate = (iso) => {
    if (!iso) return "—";
    const d = new Date(iso);
    if (isNaN(d)) return "—";
    const diff = Math.round((d - today) / (1000 * 60 * 60 * 24));
    const label = d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
    if (diff === 0) return `Today · ${label}`;
    if (diff === 1) return `Tomorrow · ${label}`;
    if (diff < 0) return label;
    return `In ${diff}d · ${label}`;
  };

  const typeColor = (type) =>
    type === "subscription"
      ? "var(--vendo-color-muted)"
      : "var(--vendo-color-text)";

  const typeLabel = (type) =>
    type === "subscription" ? "Subscription" : "Scheduled";

  return (
    <div style={{ fontFamily: "var(--vendo-font-family)", display: "grid", gap: 0 }}>
      {/* Hero total */}
      <div style={{
        background: "var(--vendo-color-surface)",
        border: "1px solid var(--vendo-color-border)",
        borderRadius: "var(--vendo-radius-large)",
        padding: "28px 28px 24px",
        marginBottom: 20,
        display: "flex",
        flexDirection: "column",
        gap: 4,
      }}>
        <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", letterSpacing: "0.01em" }}>
          Total going out
        </div>
        <div style={{ fontSize: 38, fontWeight: 700, color: "var(--vendo-color-text)", letterSpacing: "-0.02em" }}>
          {formatMoney(totalCents)}
        </div>
        <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", marginTop: 2 }}>
          {allItems.length} upcoming payment{allItems.length !== 1 ? "s" : ""}
          {schedItems.length > 0 && recItems.length > 0
            ? ` · ${schedItems.length} scheduled, ${recItems.length} subscription${recItems.length !== 1 ? "s" : ""}`
            : ""}
        </div>
      </div>

      {/* Timeline */}
      {allItems.length === 0 ? (
        <div style={{
          background: "var(--vendo-color-surface)",
          border: "1px solid var(--vendo-color-border)",
          borderRadius: "var(--vendo-radius-large)",
          padding: "32px 28px",
          color: "var(--vendo-color-muted)",
          fontSize: 14,
          textAlign: "center",
        }}>
          No upcoming payments found — you're all clear.
        </div>
      ) : (
        <div style={{
          background: "var(--vendo-color-surface)",
          border: "1px solid var(--vendo-color-border)",
          borderRadius: "var(--vendo-radius-large)",
          overflow: "hidden",
        }}>
          {allItems.map((item, idx) => {
            const isLast = idx === allItems.length - 1;
            return (
              <div key={item.id} style={{
                display: "grid",
                gridTemplateColumns: "1fr auto",
                alignItems: "center",
                padding: "16px 24px",
                borderBottom: isLast ? "none" : "1px solid var(--vendo-color-border)",
                gap: 16,
              }}>
                <div style={{ display: "flex", flexDirection: "column", gap: 3 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <span style={{
                      fontSize: 15,
                      fontWeight: 500,
                      color: "var(--vendo-color-text)",
                    }}>{item.label}</span>
                    <span style={{
                      fontSize: 11,
                      fontWeight: 500,
                      color: typeColor(item.type),
                      background: item.type === "subscription"
                        ? "rgba(144,140,133,0.10)"
                        : "rgba(17,17,17,0.07)",
                      borderRadius: "var(--vendo-radius-small)",
                      padding: "2px 7px",
                      letterSpacing: "0.02em",
                      textTransform: "uppercase",
                    }}>{typeLabel(item.type)}</span>
                  </div>
                  <div style={{ fontSize: 13, color: "var(--vendo-color-muted)" }}>
                    {formatDate(item.date)}
                  </div>
                </div>
                <div style={{
                  fontSize: 16,
                  fontWeight: 600,
                  color: "var(--vendo-color-text)",
                  textAlign: "right",
                  whiteSpace: "nowrap",
                }}>
                  {formatMoney(item.amountCents)}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
